"""
Moltbook submolt enforcement — patches urllib and requests to block unapproved submolts.
Loaded automatically by Python via user site-packages.
"""
import re as _re

_CONF = "/workspace/bin/approved-submolts.conf"
try:
    with open(_CONF) as _f:
        _APPROVED = {line.strip() for line in _f if line.strip()}
except FileNotFoundError:
    _APPROVED = {"introduction", "general", "research"}
_PATTERN = _re.compile(r"moltbook\.com/api/v1/submolts/([^/]+)/")


def _check_url(url):
    url_str = url if isinstance(url, str) else getattr(url, "full_url", str(url))
    m = _PATTERN.search(url_str)
    if m and "*" not in _APPROVED and m.group(1) not in _APPROVED:
        raise PermissionError(
            f"BLOCKED: submolt '{m.group(1)}' is not approved. "
            f"Approved: {', '.join(sorted(_APPROVED))}"
        )


# Patch urllib.request.urlopen
try:
    import urllib.request as _ur
    _orig_urlopen = _ur.urlopen

    def _patched_urlopen(url, *a, **kw):
        _check_url(url)
        return _orig_urlopen(url, *a, **kw)

    _ur.urlopen = _patched_urlopen
except Exception:
    pass

# Patch requests.Session.request (if requests is available)
try:
    import requests as _req
    _orig_request = _req.Session.request

    def _patched_request(self, method, url, *a, **kw):
        _check_url(url)
        return _orig_request(self, method, url, *a, **kw)

    _req.Session.request = _patched_request
except Exception:
    pass

# Patch http.client.HTTPSConnection to catch low-level usage
try:
    import http.client as _hc
    _orig_hc_request = _hc.HTTPSConnection.request

    def _patched_hc_request(self, method, url, *a, **kw):
        full = f"https://{self.host}{url}"
        _check_url(full)
        return _orig_hc_request(self, method, url, *a, **kw)

    _hc.HTTPSConnection.request = _patched_hc_request
except Exception:
    pass
